fun solve(nums: Array<Long>, k: Long): Long {
    val n = nums.size
    val prefixXOR = LongArray(n + 1)
    for (i in 1..n) {
        prefixXOR[i] = prefixXOR[i - 1] xor nums[i - 1]
    }

    val dp = LongArray(k + 1)
    for (i in 1..k) {
        dp[i] = Long.MAX_VALUE
    }

    for (i in 1..n) {
        dp[1] = min(dp[1], prefixXOR[i])
    }

    for (j in 2..k) {
        for (i in j..n) {
            dp[j] = min(dp[j], max(dp[j], prefixXOR[i] xor prefixXOR[i - j]))
        }
    }

    return dp[k]
}
